import sys

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = data[1]

    length = 3 ** N

    def apply_operation(s):
        new_s = []
        for i in range(0, len(s), 3):
            group = s[i:i+3]
            count_0 = group.count('0')
            count_1 = group.count('1')
            if count_1 > count_0:
                new_s.append('1')
            else:
                new_s.append('0')
        return ''.join(new_s)

    # Function to compute the final result after N operations
    def compute_final(s):
        current = s
        for _ in range(N):
            current = apply_operation(current)
        return current

    original_result = compute_final(A)
    original_value = original_result[0]

    # Precompute the positions that influence the final result
    # We use a top-down approach to determine which bits are critical
    # For each level of reduction, we track how each bit influences the next level

    def get_critical_positions(s, level):
        if level == 0:
            return [0]
        n = len(s)
        critical = []
        for i in range(0, n, 3):
            group = s[i:i+3]
            count_0 = group.count('0')
            count_1 = group.count('1')
            if count_1 > count_0:
                majority = '1'
            else:
                majority = '0'
            # Determine which positions in the group affect the majority
            if majority == '1':
                # Need at least 2 ones in the group to get majority
                if count_1 >= 2:
                    # All 3 positions are critical (since they can change the majority)
                    critical.extend([i, i+1, i+2])
                else:
                    # Only the positions with '1's are critical
                    for j in range(i, i+3):
                        if s[j] == '1':
                            critical.append(j)
            else:
                # Similar logic for '0' majority
                if count_0 >= 2:
                    critical.extend([i, i+1, i+2])
                else:
                    for j in range(i, i+3):
                        if s[j] == '0':
                            critical.append(j)
        return get_critical_positions("".join([A[i] for i in critical]), level - 1)

    critical_positions = get_critical_positions(A, N)

    # Try to find the minimum number of changes needed to flip the final result
    from itertools import combinations

    def is_possible(k):
        for bits in combinations(critical_positions, k):
            modified = list(A)
            for pos in bits:
                modified[pos] = '1' if modified[pos] == '0' else '0'
            modified_str = ''.join(modified)
            result = compute_final(modified_str)
            if result[0] != original_value:
                return True
        return False

    low, high = 0, len(critical_positions)
    answer = len(critical_positions)
    while low <= high:
        mid = (low + high) // 2
        if is_possible(mid):
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    print(answer)

